package com.nstut.buildinggadgetsextra.network;
import com.nstut.buildinggadgetsextra.common.*;import com.nstut.buildinggadgetsextra.structure.NativeStructureBridge;import net.minecraft.entity.player.ServerPlayerEntity;import net.minecraft.network.PacketBuffer;import net.minecraftforge.fml.network.NetworkEvent;import java.util.*;import java.util.function.Supplier;
public final class StructureUploadPacket{private static final Map<String,ChunkAccumulator> TRANSFERS=new HashMap<>();final UUID id;final String name;final int index,total;final byte[] data;public StructureUploadPacket(UUID id,String name,int index,int total,byte[] data){this.id=id;this.name=name;this.index=index;this.total=total;this.data=data;}public static void encode(StructureUploadPacket p,PacketBuffer b){b.writeUUID(p.id);b.writeUtf(p.name,128);b.writeVarInt(p.index);b.writeVarInt(p.total);b.writeByteArray(p.data);}public static StructureUploadPacket decode(PacketBuffer b){return new StructureUploadPacket(b.readUUID(),b.readUtf(128),b.readVarInt(),b.readVarInt(),b.readByteArray(ExtraConstants.STRUCTURE_CHUNK_SIZE));}public static void handle(StructureUploadPacket p,Supplier<NetworkEvent.Context>s){NetworkEvent.Context c=s.get();c.enqueueWork(()->{ServerPlayerEntity player=c.getSender();if(player==null||!StructureFileName.isValid(p.name))return;TRANSFERS.entrySet().removeIf(e->e.getValue().isExpired());String prefix=player.getUUID()+":";String key=prefix+p.id;if(!TRANSFERS.containsKey(key)&&TRANSFERS.keySet().stream().filter(v->v.startsWith(prefix)).count()>=4)return;try{ChunkAccumulator t=TRANSFERS.computeIfAbsent(key,k->new ChunkAccumulator(p.total));if(!t.accept(p.index,p.data)){TRANSFERS.remove(key);return;}if(t.isComplete()){TRANSFERS.remove(key);NativeStructureBridge.importStructure(player,StructureFileName.normalize(p.name),t.join());}}catch(IllegalArgumentException e){TRANSFERS.remove(key);}});c.setPacketHandled(true);}}
